#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <omp.h>

#define fp float

#ifndef NUMBER_THREADS
#define NUMBER_THREADS 256
#endif

// Inline resize function from provided source
void resize(fp* input, int input_rows, int input_cols, fp* output, int output_rows, int output_cols, int major){
	int i, j;
	int i2, j2;

	if(major == 0){
		for(i=0, i2=0; i<output_rows; i++, i2++){
			if(i2>=input_rows){
				i2 = i2 - input_rows;
			}
			for(j=0, j2=0; j<output_cols; j++, j2++){
				if(j2>=input_cols){
					j2 = j2 - input_cols;
				}
				output[i*output_cols+j] = input[i2*input_cols+j2];
			}
		}
	} else {
		for(j=0, j2=0; j<output_cols; j++, j2++){
			if(j2>=input_cols){
				j2 = j2 - input_cols;
			}
			for(i=0, i2=0; i<output_rows; i++, i2++){
				if(i2>=input_rows){
					i2 = i2 - input_rows;
				}
				output[j*output_rows+i] = input[j2*input_rows+i2];
			}
		}
	}
}

// Inline write_graphics function from provided source
void write_graphics(char* filename, fp* input, int data_rows, int data_cols, int major, int data_range){
	FILE* fid;
	int i, j;

	fid = fopen(filename, "w");
	if( fid == NULL ){
		printf( "The file was not created/opened for writing\n" );
		return;
	}

	fprintf(fid, "P2\n");
	fprintf(fid, "%d %d\n", data_cols, data_rows);
	fprintf(fid, "%d\n", data_range);

	if(major==0){
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fprintf(fid, "%d ", (int)input[i*data_cols+j]);
			}
			fprintf(fid, "\n");
		}
	} else {
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fprintf(fid, "%d ", (int)input[j*data_rows+i]);
			}
			fprintf(fid, "\n");
		}
	}

	fclose(fid);
}

// Inline read_graphics function from provided source
void read_graphics(char* filename, fp* input, int data_rows, int data_cols, int major){
	FILE* fid;
	int i, j;
	char c;
	int temp;

	fid = fopen(filename, "r");
	if( fid == NULL ){
		printf( "The file was not opened for reading\n" );
		return;
	}

	i = 0;
	while(i<3){
		c = fgetc(fid);
		if(c == '\n'){
			i = i+1;
		}
	};

	if(major==0){
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fscanf(fid, "%d", &temp);
				input[i*data_cols+j] = (fp)temp;
			}
		}
	} else {
		for(i=0; i<data_rows; i++){
			for(j=0; j<data_cols; j++){
				fscanf(fid, "%d", &temp);
				input[j*data_rows+i] = (fp)temp;
			}
		}
	}

	fclose(fid);
}

void kernel_gpu_opencl_wrapper(	fp* image,			
								int Nr,				
								int Nc,				
								long Ne,			
								int niter,			
								fp lambda,			
								long NeROI,			
								int* iN,
								int* iS,
								int* jE,
								int* jW,
								int iter,			
								int mem_size_i,
								int mem_size_j)
{
	fp* d_sums = (fp*)malloc(sizeof(fp)*Ne);
	fp* d_sums2 = (fp*)malloc(sizeof(fp)*Ne);
	fp* d_dN = (fp*)malloc(sizeof(fp)*Ne);
	fp* d_dS = (fp*)malloc(sizeof(fp)*Ne);
	fp* d_dW = (fp*)malloc(sizeof(fp)*Ne);
	fp* d_dE = (fp*)malloc(sizeof(fp)*Ne);
	fp* d_c = (fp*)malloc(sizeof(fp)*Ne);

	#pragma omp parallel for schedule(static)
	for(long ei=0; ei<Ne; ei++){
		image[ei] = exp(image[ei]/255.0f);
	}

	for(iter=0; iter<niter; iter++){
		#pragma omp parallel for schedule(static)
		for(long ei=0; ei<Ne; ei++){
			d_sums[ei] = image[ei];
			d_sums2[ei] = image[ei]*image[ei];
		}

		long no = Ne;
		int mul = 1;
		int blocks2_work_size = (int)((no + NUMBER_THREADS - 1)/NUMBER_THREADS);
		while(blocks2_work_size > 0){
			int gridDim = blocks2_work_size;
			fp* d_psum = (fp*)malloc(sizeof(fp)*NUMBER_THREADS);
			fp* d_psum2 = (fp*)malloc(sizeof(fp)*NUMBER_THREADS);

			#pragma omp parallel for schedule(static)
			for(int bx=0; bx<gridDim; bx++){
				int nf = NUMBER_THREADS - (gridDim*NUMBER_THREADS - (int)no);
				int df = 0;
				int tx;

				for(tx=0; tx<NUMBER_THREADS; tx++){
					int ei = bx*NUMBER_THREADS + tx;
					if(ei < no){
						d_psum[tx] = d_sums[ei*mul];
						d_psum2[tx] = d_sums2[ei*mul];
					} else {
						d_psum[tx] = 0.0f;
						d_psum2[tx] = 0.0f;
					}
				}

				if(nf == NUMBER_THREADS){
					for(int i=2; i<=NUMBER_THREADS; i*=2){
						for(tx=0; tx<NUMBER_THREADS; tx++){
							if(((tx+1) % i) == 0){
								d_psum[tx] += d_psum[tx - i/2];
								d_psum2[tx] += d_psum2[tx - i/2];
							}
						}
					}
					d_sums[bx*mul*NUMBER_THREADS] = d_psum[NUMBER_THREADS-1];
					d_sums2[bx*mul*NUMBER_THREADS] = d_psum2[NUMBER_THREADS-1];
				} else {
					if(bx != (gridDim - 1)){
						for(int i=2; i<=NUMBER_THREADS; i*=2){
							for(tx=0; tx<NUMBER_THREADS; tx++){
								if(((tx+1) % i) == 0){
									d_psum[tx] += d_psum[tx - i/2];
									d_psum2[tx] += d_psum2[tx - i/2];
								}
							}
						}
						d_sums[bx*mul*NUMBER_THREADS] = d_psum[NUMBER_THREADS-1];
						d_sums2[bx*mul*NUMBER_THREADS] = d_psum2[NUMBER_THREADS-1];
					} else {
						for(int i=2; i<=NUMBER_THREADS; i*=2){
							if(nf >= i){
								df = i;
							}
						}
						for(int i=2; i<=df; i*=2){
							for(tx=0; tx<NUMBER_THREADS; tx++){
								if(((tx+1) % i) == 0 && tx < df){
									d_psum[tx] += d_psum[tx - i/2];
									d_psum2[tx] += d_psum2[tx - i/2];
								}
							}
						}
						int tx_last = df - 1;
						for(int i=(bx*NUMBER_THREADS)+df; i<(bx*NUMBER_THREADS)+nf; i++){
							d_psum[tx_last] += d_sums[i];
							d_psum2[tx_last] += d_sums2[i];
						}
						d_sums[bx*mul*NUMBER_THREADS] = d_psum[tx_last];
						d_sums2[bx*mul*NUMBER_THREADS] = d_psum2[tx_last];
					}
				}
			}
			free(d_psum);
			free(d_psum2);

			no = blocks2_work_size;
			if(blocks2_work_size == 1){
				blocks2_work_size = 0;
			} else {
				mul = mul * NUMBER_THREADS;
				int blocks_x = blocks2_work_size / NUMBER_THREADS;
				if(blocks2_work_size % NUMBER_THREADS != 0){
					blocks_x++;
				}
				blocks2_work_size = blocks_x;
			}
		}

		fp total = d_sums[0];
		fp total2 = d_sums2[0];
		fp meanROI = total / (fp)(NeROI);
		fp meanROI2 = meanROI * meanROI;
		fp varROI = (total2 / (fp)(NeROI)) - meanROI2;
		fp q0sqr = varROI / meanROI2;

		#pragma omp parallel for schedule(static)
		for(long ei=0; ei<Ne; ei++){
			int row = (ei+1) % Nr - 1;
			int col = (ei+1) / Nr;
			if(((ei+1) % Nr) == 0){
				row = Nr - 1;
				col -= 1;
			}
			if(ei < Ne){
				fp d_Jc = image[ei];
				fp d_dN_loc = image[iN[row] + Nr*col] - d_Jc;
				fp d_dS_loc = image[iS[row] + Nr*col] - d_Jc;
				fp d_dW_loc = image[row + Nr*jW[col]] - d_Jc;
				fp d_dE_loc = image[row + Nr*jE[col]] - d_Jc;

				fp d_G2 = (d_dN_loc*d_dN_loc + d_dS_loc*d_dS_loc + d_dW_loc*d_dW_loc + d_dE_loc*d_dE_loc) / (d_Jc*d_Jc);
				fp d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;
				fp d_num = (0.5f*d_G2) - ((1.0f/16.0f)*(d_L*d_L));
				fp d_den = 1.0f + (0.25f*d_L);
				fp d_qsqr = d_num/(d_den*d_den);

				d_den = (d_qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
				fp d_c_loc = 1.0f / (1.0f + d_den);

				if(d_c_loc < 0.0f) d_c_loc = 0.0f;
				else if(d_c_loc > 1.0f) d_c_loc = 1.0f;

				d_dN[ei] = d_dN_loc;
				d_dS[ei] = d_dS_loc;
				d_dW[ei] = d_dW_loc;
				d_dE[ei] = d_dE_loc;
				d_c[ei] = d_c_loc;
			}
		}

		#pragma omp parallel for schedule(static)
		for(long ei=0; ei<Ne; ei++){
			int row = (ei+1) % Nr - 1;
			int col = (ei+1) / Nr;
			if(((ei+1) % Nr) == 0){
				row = Nr - 1;
				col -= 1;
			}
			if(ei < Ne){
				fp d_cN = d_c[ei];
				fp d_cS = d_c[iS[row] + Nr*col];
				fp d_cW = d_c[ei];
				fp d_cE = d_c[row + Nr*jE[col]];

				fp d_D = d_cN*d_dN[ei] + d_cS*d_dS[ei] + d_cW*d_dW[ei] + d_cE*d_dE[ei];

				image[ei] = image[ei] + 0.25f*lambda*d_D;
			}
		}
	}

	#pragma omp parallel for schedule(static)
	for(long ei=0; ei<Ne; ei++){
		image[ei] = log(image[ei])*255.0f;
	}

	free(d_sums);
	free(d_sums2);
	free(d_dN);
	free(d_dS);
	free(d_dW);
	free(d_dE);
	free(d_c);
}

int platform_id_inuse = 0;            
int device_id_inuse = 0;              

int main(int argc, char* argv[]){
  printf("WG size of kernel = %d \n", NUMBER_THREADS);

	fp* image_ori;																
	int image_ori_rows;
	int image_ori_cols;
	long image_ori_elem;

	fp* image;															
	int Nr=0,Nc=0;													
	long Ne=0;

	int niter=0;																
	fp lambda=0.0f;															

	int r1,r2,c1,c2;												
	long NeROI=0;														

	int* iN;
	int* iS;
	int* jE;
	int* jW;

	int iter=0;   
	long i=0;    
	long j=0;    

	int mem_size_i=0;
	int mem_size_j=0;

    int cur_arg;
	for (cur_arg = 1; argc > cur_arg; cur_arg++) {
        if (strcmp(argv[cur_arg], "-n") == 0) {
            if (cur_arg + 1 <= argc) {
		        niter = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-l") == 0) {
            if (argc >= cur_arg + 1) {
		        lambda = (fp)atof(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-s") == 0) {
            if (cur_arg + 2 <= argc) {
                Nr = atoi(argv[cur_arg+1]);			
        		Nc = atoi(argv[cur_arg+2]);			
                cur_arg += 2;
            }
        }
        else if (strcmp(argv[cur_arg], "-p") == 0) {
            if (cur_arg + 1 <= argc) {
                platform_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-d") == 0) {
            if (cur_arg + 1 <= argc) {
                device_id_inuse = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
    }

	image_ori_rows = 502;
	image_ori_cols = 458;
	image_ori_elem = image_ori_rows * image_ori_cols;

	image_ori = (fp*)malloc(sizeof(fp) * image_ori_elem);

	read_graphics(	"../../data/srad/image.pgm",
					image_ori,
					image_ori_rows,
					image_ori_cols,
					1);

	Ne = Nr*Nc;

	image = (fp*)malloc(sizeof(fp) * Ne);

	resize(	image_ori,
				image_ori_rows,
				image_ori_cols,
				image,
				Nr,
				Nc,
				1);

	r1     = 0;											
	r2     = Nr - 1;									
	c1     = 0;											
	c2     = Nc - 1;									

	NeROI = (r2-r1+1)*(c2-c1+1);											

	mem_size_i = sizeof(int) * Nr;											
	iN = (int *)malloc(mem_size_i) ;										
	iS = (int *)malloc(mem_size_i) ;										
	mem_size_j = sizeof(int) * Nc;											
	jW = (int *)malloc(mem_size_j) ;										
	jE = (int *)malloc(mem_size_j) ;										

	for (i=0; i<Nr; i++) {
		iN[i] = i-1;														
		iS[i] = i+1;														
	}
	for (j=0; Nc > j; j++) {
		jW[j] = j-1;														
		jE[j] = j+1;														
	}

	iN[0]    = 0;															
	iS[Nr-1] = Nr-1;														
	jW[0]    = 0;															
	jE[Nc-1] = Nc-1;														

	kernel_gpu_opencl_wrapper(	image,										
								Nr,											
								Nc,											
								Ne,											
								niter,										
								lambda,										
								NeROI,										
								iN,
								iS,
								jE,
								jW,
								iter,										
								mem_size_i,
								mem_size_j);

	write_graphics(	"./output/image_out.pgm",
					image,
					Nr,
					Nc,
					1,
					255);

	free(image_ori);
	free(image);
	free(iN); 
	free(iS); 
	free(jW); 
	free(jE);

	return 0;
}
